settings.custom_liquid:
{% assign is_de = false %}
{% if request.host contains 'roolo.de' or localization.language.iso_code == 'de' %}
  {% assign is_de = true %}
{% endif %}

<section class="roolo-hero-premium">
  <div class="roolo-hero-premium__text">
    <div class="roolo-hero-premium__eyebrow">
      {% if is_de %}
        DEIN STIL, DEINE REISE, DEIN ROOLO.
      {% else %}
        JOUW STIJL, JOUW REIS, JOUW ROOLO.
      {% endif %}
    </div>

    <h1>
      {% if is_de %}
        Bestseller, die deinen<br>
        Alltag aufwerten.
      {% else %}
        Bestsellers die je<br>
        dagelijks leven upgraden.
      {% endif %}
    </h1>

    <p>
      {% if is_de %}
        Sorgfältig ausgewählte Produkte für Stil, Reisen und Komfort —
        gemacht, um dich überall zu begleiten.
      {% else %}
        Zorgvuldig geselecteerde producten voor stijl, reizen en comfort —
        gemaakt om met je mee te gaan.
      {% endif %}
    </p>

    <a href="{% if is_de %}https://roolo.de/collections/bestsellers{% else %}https://roolo.nl/collections/bestsellers{% endif %}" class="roolo-hero-premium__button">
      {% if is_de %}
        Bestseller shoppen
      {% else %}
        Shop bestsellers
      {% endif %}
    </a>
  </div>

  <div class="roolo-hero-premium__image-wrap">
    <picture>
      <source
        media="(max-width: 749px)"
        srcset="https://cdn.shopify.com/s/files/1/0773/7458/7204/files/ChatGPT_Image_6_mei_2026_18_25_54_2.png?v=1778084758"
      >
      <img
        src="https://cdn.shopify.com/s/files/1/0773/7458/7204/files/ChatGPT_Image_6_mei_2026_18_25_54_2.png?v=1778084758"
        alt="{% if is_de %}ROOLO Premium Essentials{% else %}ROOLO premium essentials{% endif %}"
        loading="eager"
      >
    </picture>
  </div>
</section>

<style>
.roolo-hero-premium {
  width: 100%;
  display: grid;
  grid-template-columns: 47% 53%;
  height: 480px;
  background: #f4eee6;
  overflow: hidden;
}

.roolo-hero-premium__text {
  position: relative;
  z-index: 2;
  padding: 34px 7vw 34px;
  display: flex;
  flex-direction: column;
  justify-content: center;
}

.roolo-hero-premium__eyebrow {
  display: inline-flex;
  width: fit-content;
  align-items: center;
  margin-bottom: 16px;
  padding: 8px 12px;
  border: 1px solid rgba(0,0,0,0.12);
  border-radius: 8px;
  background: rgba(255,255,255,0.52);
  color: #111;
  font-size: 12px;
  line-height: 1;
  letter-spacing: 0.08em;
  font-weight: 850;
}

.roolo-hero-premium h1 {
  margin: 0;
  color: #111;
  font-size: clamp(38px, 4.2vw, 62px);
  line-height: 0.97;
  letter-spacing: -0.058em;
  font-weight: 500;
  font-family: Georgia, 'Times New Roman', serif;
}

.roolo-hero-premium p {
  max-width: 500px;
  margin: 20px 0 0;
  color: #242424;
  font-size: 16px;
  line-height: 1.45;
  font-weight: 450;
}

.roolo-hero-premium__button {
  display: inline-flex;
  width: fit-content;
  align-items: center;
  justify-content: center;
  margin-top: 24px;
  min-height: 52px;
  padding: 0 30px;
  border-radius: 9px;
  background: #0d0d0d;
  color: #fff;
  text-decoration: none;
  font-size: 15px;
  font-weight: 850;
  transition: transform 0.2s ease, background 0.2s ease;
}

.roolo-hero-premium__button:hover {
  transform: translateY(-2px);
  background: #000;
}

.roolo-hero-premium__image-wrap {
  position: relative;
  height: 480px;
  overflow: hidden;
  background: #f4eee6;
}

.roolo-hero-premium__image-wrap picture,
.roolo-hero-premium__image-wrap img {
  width: 100%;
  height: 100%;
  display: block;
}

.roolo-hero-premium__image-wrap img {
  object-fit: cover;
  object-position: center 60%;
  transform: scale(0.92);
  transform-origin: center center;
}

.roolo-hero-premium__image-wrap::before {
  content: "";
  position: absolute;
  inset: 0;
  z-index: 1;
  pointer-events: none;
  background: linear-gradient(
    90deg,
    rgba(244,238,230,0.82) 0%,
    rgba(244,238,230,0.22) 23%,
    rgba(244,238,230,0) 48%
  );
}

@media screen and (max-width: 989px) {
  .roolo-hero-premium {
    height: 500px;
    grid-template-columns: 50% 50%;
  }

  .roolo-hero-premium__text {
    padding: 34px 5vw;
  }

  .roolo-hero-premium h1 {
    font-size: 44px;
  }

  .roolo-hero-premium p {
    font-size: 15px;
  }

  .roolo-hero-premium__image-wrap {
    height: 500px;
  }

  .roolo-hero-premium__image-wrap img {
    object-position: center 62%;
    transform: scale(0.93);
  }
}

@media screen and (max-width: 749px) {
  .roolo-hero-premium {
    display: flex;
    flex-direction: column;
    height: auto;
    background: #f4eee6;
  }

  .roolo-hero-premium__image-wrap {
    order: 1;
    width: 100%;
    height: 430px;
    min-height: 430px;
  }

  .roolo-hero-premium__image-wrap img {
    object-fit: cover;
    object-position: center 78%;
    transform: none;
  }

  .roolo-hero-premium__image-wrap::before {
    display: none;
  }

  .roolo-hero-premium__text {
    order: 2;
    width: 100%;
    padding: 26px 20px 30px;
    background: #f4eee6;
    justify-content: flex-start;
  }

  .roolo-hero-premium__eyebrow {
    margin-bottom: 12px;
    padding: 7px 10px;
    background: rgba(255,255,255,0.6);
    border-color: rgba(0,0,0,0.08);
    color: #111;
    font-size: 10px;
    letter-spacing: 0.07em;
  }

  .roolo-hero-premium h1 {
    color: #111;
    font-size: 42px;
    line-height: 0.98;
    letter-spacing: -0.055em;
    text-shadow: none;
  }

  .roolo-hero-premium p {
    color: #222;
    font-size: 15px;
    line-height: 1.5;
    margin-top: 16px;
    max-width: 100%;
    text-shadow: none;
  }

  .roolo-hero-premium__button {
    width: 100%;
    min-height: 52px;
    margin-top: 22px;
    border-radius: 10px;
    background: #111;
    color: #fff;
  }
}
</style>

{% assign is_de = false %}
{% if request.host contains 'roolo.de' or localization.language.iso_code == 'de' %}
  {% assign is_de = true %}
{% endif %}

<section class="roolo-trust-bar">
  <div class="roolo-trust-bar__inner">
    <div class="roolo-trust-bar__item">
      {% if is_de %}
        Kostenloser Versand ab €20
      {% else %}
        Gratis verzending vanaf €20
      {% endif %}
    </div>

    <div class="roolo-trust-bar__item">
      {% if is_de %}
        30 Tage Bedenkzeit
      {% else %}
        30 dagen bedenktijd
      {% endif %}
    </div>

    <div class="roolo-trust-bar__item">
      {% if is_de %}
        Später bezahlen mit Klarna
      {% else %}
        Betaal later met Klarna
      {% endif %}
    </div>
  </div>
</section>

<style>
.roolo-trust-bar {
  background: #fff;
  padding: 18px 20px;
  border-bottom: 1px solid rgba(0,0,0,0.06);
}

.roolo-trust-bar__inner {
  max-width: 1180px;
  margin: 0 auto;
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 14px;
}

.roolo-trust-bar__item {
  background: #f7f3ee;
  border: 1px solid rgba(0,0,0,0.06);
  border-radius: 14px;
  padding: 15px 18px;
  text-align: center;
  font-size: 14px;
  font-weight: 750;
  color: #111;
}

@media screen and (max-width: 749px) {
  .roolo-trust-bar {
    padding: 12px 14px;
  }

  .roolo-trust-bar__inner {
    grid-template-columns: 1fr;
    gap: 8px;
  }

  .roolo-trust-bar__item {
    padding: 12px 14px;
    font-size: 13px;
    border-radius: 12px;
  }
}
</style>

{% assign is_de = false %}
{% if request.host contains 'roolo.de' or localization.language.iso_code == 'de' %}
  {% assign is_de = true %}
{% endif %}

<section class="roolo-featured-products" id="rooloFeaturedProducts">
  <div class="roolo-featured-products__inner">
    <div class="roolo-featured-products__header">
      <span>
        {% if is_de %}
          AUSGEWÄHLTE BESTSELLER
        {% else %}
          UITGELICHTE BESTSELLERS
        {% endif %}
      </span>

      <h2>
        {% if is_de %}
          Entdecke unsere beliebtesten Produkte.
        {% else %}
          Ontdek onze populairste producten.
        {% endif %}
      </h2>
    </div>

    <div class="roolo-featured-products__slider-wrap">
      <div class="roolo-featured-products__grid" id="rooloFeaturedTrack">

        <!-- Product 1: LIFT Pure -->
        <a
          href="{% if is_de %}https://roolo.de/products/lift-pure-de{% else %}https://roolo.nl/products/lift-pure{% endif %}"
          class="roolo-featured-product-card"
        >
          <div class="roolo-featured-product-card__image">
            <img
              src="https://cdn.shopify.com/s/files/1/0773/7458/7204/files/pure.png?v=1782152681"
              alt="{% if is_de %}LIFT Pure weiße Sneaker{% else %}LIFT Pure witte sneakers{% endif %}"
              loading="lazy"
            >
          </div>

          <div class="roolo-featured-product-card__content">
            <div>
              <span class="roolo-featured-product-card__label">
                {% if is_de %}NEU{% else %}NIEUW{% endif %}
              </span>

              <h3>LIFT Pure</h3>

              <p>
                {% if is_de %}
                  Cleanes weißes Design mit diskreter Extra-Höhe.
                {% else %}
                  Clean wit design met onzichtbare extra lengte.
                {% endif %}
              </p>
            </div>

            <span class="roolo-featured-product-card__arrow">→</span>
          </div>
        </a>

        <!-- Product 2: LIFT Casual -->
        <a
          href="{% if is_de %}https://roolo.de/products/lift-casual-de{% else %}https://roolo.nl/products/lift-casual{% endif %}"
          class="roolo-featured-product-card"
        >
          <div class="roolo-featured-product-card__image">
            <img
              src="https://cdn.shopify.com/s/files/1/0773/7458/7204/files/casual.png?v=1782152681"
              alt="{% if is_de %}LIFT Casual Herren{% else %}LIFT Casual heren{% endif %}"
              loading="lazy"
            >
          </div>

          <div class="roolo-featured-product-card__content">
            <div>
              <span class="roolo-featured-product-card__label">
                {% if is_de %}HERREN{% else %}HEREN{% endif %}
              </span>

              <h3>LIFT Casual</h3>

              <p>
                {% if is_de %}
                  Dezenter Style mit extra Höhe für jeden Tag.
                {% else %}
                  Subtiele stijl met extra lengte voor elke dag.
                {% endif %}
              </p>
            </div>

            <span class="roolo-featured-product-card__arrow">→</span>
          </div>
        </a>

        <!-- Product 3: LIFT Essential -->
        <a
          href="{% if is_de %}https://roolo.de/products/lift-essential-de{% else %}https://roolo.nl/products/lift-essential?_pos=1&_psq=ess&_ss=e&_v=1.0{% endif %}"
          class="roolo-featured-product-card"
        >
          <div class="roolo-featured-product-card__image">
            <img
              src="https://cdn.shopify.com/s/files/1/0773/7458/7204/files/essential.png?v=1782152681"
              alt="{% if is_de %}LIFT Essential Herren{% else %}LIFT Essential heren{% endif %}"
              loading="lazy"
            >
          </div>

          <div class="roolo-featured-product-card__content">
            <div>
              <span class="roolo-featured-product-card__label">
                {% if is_de %}HERREN{% else %}HEREN{% endif %}
              </span>

              <h3>LIFT Essential</h3>

              <p>
                {% if is_de %}
                  Sportlicher Look mit extra Höhe für jeden Tag.
                {% else %}
                  Sportieve look met extra lengte voor elke dag.
                {% endif %}
              </p>
            </div>

            <span class="roolo-featured-product-card__arrow">→</span>
          </div>
        </a>

        <!-- Product 4: LIFT Shoewear -->
        <a
          href="{% if is_de %}https://roolo.de/products/de-lift-shoewear{% else %}https://roolo.nl/products/lift-sneakers{% endif %}"
          class="roolo-featured-product-card"
        >
          <div class="roolo-featured-product-card__image">
            <img
              src="https://cdn.shopify.com/s/files/1/0773/7458/7204/files/sneaker.png?v=1782152681"
              alt="{% if is_de %}LIFT Shoewear Herren{% else %}LIFT Shoewear heren{% endif %}"
              loading="lazy"
            >
          </div>

          <div class="roolo-featured-product-card__content">
            <div>
              <span class="roolo-featured-product-card__label">
                {% if is_de %}KOLLEKTION{% else %}COLLECTIE{% endif %}
              </span>

              <h3>LIFT Shoewear</h3>

              <p>
                {% if is_de %}
                  Wähle deinen Style und erhalte bis zu +10 cm extra Höhe.
                {% else %}
                  Kies jouw stijl en krijg tot +10 cm extra lengte.
                {% endif %}
              </p>
            </div>

            <span class="roolo-featured-product-card__arrow">→</span>
          </div>
        </a>

        <!-- Product 5: Roolo Bag -->
        <a
          href="{% if is_de %}https://roolo.de/products/roolo-bag-anti-diebstahl-tasche{% else %}https://roolo.nl/products/roolo-bag{% endif %}"
          class="roolo-featured-product-card"
        >
          <div class="roolo-featured-product-card__image">
            <img
              src="https://cdn.shopify.com/s/files/1/0773/7458/7204/files/ChatGPT_Image_6_mei_2026_21_15_46_3.png?v=1778094966"
              alt="{% if is_de %}Roolo Bag Anti-Diebstahl Tasche{% else %}Roolo Bag anti-diefstal tas{% endif %}"
              loading="lazy"
            >
          </div>

          <div class="roolo-featured-product-card__content">
            <div>
              <span class="roolo-featured-product-card__label">
                {% if is_de %}REISE & ALLTAG{% else %}REIS & DAGELIJKS{% endif %}
              </span>

              <h3>Roolo Bag</h3>

              <p>
                {% if is_de %}
                  Anti-Diebstahl Tasche für unterwegs.
                {% else %}
                  Anti-diefstal tas voor onderweg.
                {% endif %}
              </p>
            </div>

            <span class="roolo-featured-product-card__arrow">→</span>
          </div>
        </a>

      </div>

      <button class="roolo-featured-products__nav roolo-featured-products__nav--prev" type="button" aria-label="{% if is_de %}Vorherige Produkte{% else %}Vorige producten{% endif %}">
        ←
      </button>

      <button class="roolo-featured-products__nav roolo-featured-products__nav--next" type="button" aria-label="{% if is_de %}Nächste Produkte{% else %}Volgende producten{% endif %}">
        →
      </button>
    </div>
  </div>
</section>

<style>
.roolo-featured-products {
  background: #ffffff;
  padding: 34px 20px 42px;
}

.roolo-featured-products__inner {
  max-width: 1180px;
  margin: 0 auto;
}

.roolo-featured-products__header {
  text-align: center;
  margin-bottom: 26px;
}

.roolo-featured-products__header span {
  display: inline-flex;
  margin-bottom: 10px;
  font-size: 11px;
  line-height: 1;
  letter-spacing: 0.13em;
  font-weight: 850;
  color: rgba(0,0,0,0.55);
}

.roolo-featured-products__header h2 {
  margin: 0;
  color: #111;
  font-family: Georgia, 'Times New Roman', serif;
  font-size: clamp(30px, 3.2vw, 46px);
  line-height: 1.05;
  letter-spacing: -0.05em;
  font-weight: 500;
}

.roolo-featured-products__slider-wrap {
  position: relative;
}

.roolo-featured-products__grid {
  display: flex;
  gap: 18px;
  overflow-x: auto;
  scroll-snap-type: x mandatory;
  scroll-behavior: smooth;
  padding: 0 2px 10px;
  -webkit-overflow-scrolling: touch;
}

.roolo-featured-products__grid::-webkit-scrollbar {
  display: none;
}

.roolo-featured-product-card {
  flex: 0 0 calc((100% - 36px) / 3);
  scroll-snap-align: start;
  display: block;
  text-decoration: none;
  color: inherit;
  border-radius: 24px;
  overflow: hidden;
  background: #f6f3ef;
  border: 1px solid rgba(0,0,0,0.06);
  box-shadow: 0 14px 34px rgba(0,0,0,0.055);
  transition: transform 0.22s ease, box-shadow 0.22s ease;
}

.roolo-featured-product-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 20px 44px rgba(0,0,0,0.085);
}

.roolo-featured-product-card__image {
  height: 285px;
  overflow: hidden;
  background: #f4eee6;
}

.roolo-featured-product-card__image img {
  width: 100%;
  height: 100%;
  display: block;
  object-fit: cover;
  object-position: center center;
  transition: transform 0.35s ease;
}

.roolo-featured-product-card:hover .roolo-featured-product-card__image img {
  transform: scale(1.035);
}

.roolo-featured-product-card__content {
  padding: 20px 22px 22px;
  background: #f6f3ef;
  border-top: 1px solid rgba(0,0,0,0.055);
  display: flex;
  align-items: flex-end;
  justify-content: space-between;
  gap: 14px;
  min-height: 138px;
}

.roolo-featured-product-card__label {
  display: inline-flex;
  margin-bottom: 9px;
  padding: 6px 9px;
  border-radius: 999px;
  background: #fff;
  color: rgba(0,0,0,0.66);
  font-size: 10px;
  line-height: 1;
  letter-spacing: 0.11em;
  font-weight: 850;
  border: 1px solid rgba(0,0,0,0.06);
}

.roolo-featured-product-card h3 {
  margin: 0;
  color: #111;
  font-family: Georgia, 'Times New Roman', serif;
  font-size: 30px;
  line-height: 1;
  letter-spacing: -0.045em;
  font-weight: 500;
}

.roolo-featured-product-card p {
  margin: 8px 0 0;
  color: rgba(0,0,0,0.68);
  font-size: 14px;
  line-height: 1.35;
  font-weight: 650;
  max-width: 250px;
}

.roolo-featured-product-card__arrow {
  flex: 0 0 auto;
  width: 42px;
  height: 42px;
  border-radius: 999px;
  background: #111;
  color: #fff;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 22px;
  line-height: 1;
  font-weight: 700;
  transition: transform 0.2s ease;
}

.roolo-featured-product-card:hover .roolo-featured-product-card__arrow {
  transform: translateX(3px);
}

.roolo-featured-products__nav {
  position: absolute;
  top: 34%;
  z-index: 5;
  width: 46px;
  height: 46px;
  border-radius: 999px;
  border: 1px solid rgba(0,0,0,0.08);
  background: rgba(255,255,255,0.94);
  color: #111;
  box-shadow: 0 12px 30px rgba(0,0,0,0.12);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  font-size: 22px;
  font-weight: 800;
  transition: transform 0.2s ease, background 0.2s ease;
}

.roolo-featured-products__nav:hover {
  transform: translateY(-2px);
  background: #fff;
}

.roolo-featured-products__nav--prev {
  left: -18px;
}

.roolo-featured-products__nav--next {
  right: -18px;
}

@media screen and (max-width: 989px) {
  .roolo-featured-products__grid {
    gap: 14px;
  }

  .roolo-featured-product-card {
    flex: 0 0 calc((100% - 28px) / 3);
  }

  .roolo-featured-product-card__image {
    height: 250px;
  }

  .roolo-featured-product-card__content {
    padding: 18px;
    min-height: 132px;
  }

  .roolo-featured-product-card h3 {
    font-size: 25px;
  }

  .roolo-featured-product-card p {
    font-size: 13px;
  }

  .roolo-featured-products__nav {
    width: 42px;
    height: 42px;
  }

  .roolo-featured-products__nav--prev {
    left: -8px;
  }

  .roolo-featured-products__nav--next {
    right: -8px;
  }
}

/* MOBILE */
@media screen and (max-width: 749px) {
  .roolo-featured-products {
    padding: 30px 0 36px;
    overflow: hidden;
  }

  .roolo-featured-products__inner {
    max-width: none;
    width: 100%;
  }

  .roolo-featured-products__header {
    text-align: left;
    margin-bottom: 20px;
    padding: 0 26px;
  }

  .roolo-featured-products__header h2 {
    font-size: 32px;
  }

  .roolo-featured-products__grid {
    gap: 14px;
    padding: 0 0 8px;
    scroll-padding-left: 22px;
  }

  .roolo-featured-product-card {
    flex: 0 0 78%;
    border-radius: 22px;
  }

  .roolo-featured-product-card:first-child {
    margin-left: 22px;
  }

  .roolo-featured-product-card:last-child {
    margin-right: 22px;
  }

  .roolo-featured-product-card__image {
    height: 270px;
  }

  .roolo-featured-product-card__content {
    padding: 18px;
    min-height: 135px;
  }

  .roolo-featured-product-card h3 {
    font-size: 27px;
  }

  .roolo-featured-product-card p {
    font-size: 13.5px;
  }

  .roolo-featured-product-card__arrow {
    width: 40px;
    height: 40px;
    font-size: 20px;
  }

  .roolo-featured-products__nav {
    display: none;
  }
}
</style>

<script>
  (function() {
    var section = document.getElementById('rooloFeaturedProducts');
    if (!section) return;

    var track = section.querySelector('#rooloFeaturedTrack');
    var next = section.querySelector('.roolo-featured-products__nav--next');
    var prev = section.querySelector('.roolo-featured-products__nav--prev');

    if (!track || !next || !prev) return;

    function getScrollAmount() {
      var card = track.querySelector('.roolo-featured-product-card');
      if (!card) return 350;
      var styles = window.getComputedStyle(track);
      var gap = parseFloat(styles.columnGap || styles.gap || 18) || 18;
      return card.offsetWidth + gap;
    }

    next.addEventListener('click', function() {
      track.scrollBy({
        left: getScrollAmount(),
        behavior: 'smooth'
      });
    });

    prev.addEventListener('click', function() {
      track.scrollBy({
        left: -getScrollAmount(),
        behavior: 'smooth'
      });
    });
  })();
</script>

